/* ================================================================
   CSR Page — csr.css  (Redesigned)
   ================================================================ */

/* ── Tokens ── */
:root {
  --gold:        #c9a24d;
  --gold-light:  #f6c453;
  --gold-grad:   linear-gradient(135deg, #f6c453 0%, #c9a24d 100%);
  --ink:         #0e0e0e;
  --ink-2:       #1a1a1a;
  --off-white:   #f9f7f3;
  --warm-gray:   #f3f0ea;
  --text-muted:  #777065;
  --ease-out:    cubic-bezier(0.22, 1, 0.36, 1);
}

/* ================================================================
   BASE REVEAL ANIMATIONS
   ================================================================ */
.reveal {
  opacity: 0;
  transform: translateY(44px);
  transition: opacity 0.85s var(--ease-out), transform 0.85s var(--ease-out);
}
.reveal.left  { transform: translateX(-48px); }
.reveal.right { transform: translateX(48px); }
.reveal.zoom  { transform: scale(0.94); }
.reveal.active {
  opacity: 1;
  transform: translate(0) scale(1);
}

/* ================================================================
   SECTION SHARED
   ================================================================ */
.csr-tag {
  display: inline-block;
  font-size: 10.5px;
  font-weight: 700;
  letter-spacing: 3.5px;
  text-transform: uppercase;
  color: var(--gold);
  padding: 7px 18px;
  border: 1px solid rgba(201, 162, 77, 0.28);
  border-radius: 40px;
  background: rgba(201, 162, 77, 0.07);
}

/* ================================================================
   INTRO SECTION
   ================================================================ */
.csr-intro {
  background: var(--off-white);
  padding: 120px 0 130px;
}

.csr-intro-grid {
  display: grid;
  grid-template-columns: 1.05fr 0.95fr;
  gap: 96px;
  align-items: center;
}

/* Left text */
.csr-text h2 {
  font-size: clamp(38px, 4.5vw, 56px);
  font-weight: 700;
  margin: 20px 0 28px;
  color: var(--ink);
  line-height: 1.18;
  letter-spacing: -0.5px;
}

.csr-text h2 em {
  font-style: italic;
  background: var(--gold-grad);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.csr-text p {
  font-size: 15.5px;
  line-height: 1.85;
  color: var(--text-muted);
  margin-bottom: 18px;
}

/* Stat row */
.csr-intro-stat-row {
  display: flex;
  align-items: center;
  gap: 28px;
  margin-top: 44px;
  padding-top: 36px;
  border-top: 1px solid rgba(201, 162, 77, 0.2);
}

.csr-stat {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.csr-stat-num {
  font-size: 28px;
  font-weight: 800;
  color: var(--ink);
  letter-spacing: -1px;
  line-height: 1;
}

.csr-stat-label {
  font-size: 11px;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: var(--text-muted);
  font-weight: 600;
}

.csr-stat-divider {
  width: 1px;
  height: 40px;
  background: rgba(201, 162, 77, 0.25);
  flex-shrink: 0;
}

/* Right image */
.csr-image {
  position: relative;
}

.csr-image-frame {
  position: relative;
  border-radius: 28px;
  overflow: hidden;
  box-shadow:
    0 4px 0 0 rgba(201, 162, 77, 0.35),
    0 32px 80px rgba(0,0,0,0.12);
}

.csr-image-frame::before {
  content: '';
  position: absolute;
  inset: 0;
  border: 2px solid rgba(201, 162, 77, 0.18);
  border-radius: inherit;
  z-index: 2;
  pointer-events: none;
}

.csr-image-frame img {
  width: 100%;
  display: block;
  transition: transform 0.7s var(--ease-out);
}

.csr-image:hover .csr-image-frame img {
  transform: scale(1.04);
}

/* Year badge */
.csr-image-badge {
  position: absolute;
  bottom: -18px;
  left: -18px;
  background: var(--ink);
  border: 2px solid rgba(201, 162, 77, 0.3);
  border-radius: 18px;
  padding: 14px 22px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1px;
  box-shadow: 0 16px 48px rgba(0,0,0,0.25);
}

.csr-image-badge span {
  font-size: 10px;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: rgba(201, 162, 77, 0.7);
  font-weight: 600;
}

.csr-image-badge strong {
  font-size: 24px;
  font-weight: 800;
  color: var(--gold-light);
  letter-spacing: -0.5px;
  line-height: 1;
}

/* ================================================================
   SECTION HEADER (shared)
   ================================================================ */
.csr-section-header {
  text-align: center;
  margin-bottom: 72px;
}

.csr-section-header h2 {
  font-size: clamp(36px, 4vw, 52px);
  font-weight: 700;
  color: var(--ink);
  margin: 16px 0 18px;
  letter-spacing: -0.4px;
  line-height: 1.15;
}

.csr-section-header h2 em {
  font-style: italic;
  background: var(--gold-grad);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.csr-section-sub {
  font-size: 16px;
  color: var(--text-muted);
  max-width: 480px;
  margin: 0 auto;
  line-height: 1.7;
}

/* ================================================================
   INITIATIVES SECTION
   ================================================================ */
.csr-initiatives {
  background: var(--warm-gray);
  padding: 120px 0 130px;
  position: relative;
  overflow: hidden;
}

/* Subtle dot-grid background */
.csr-initiatives::before {
  content: '';
  position: absolute;
  inset: 0;
  background-image: radial-gradient(rgba(201,162,77,0.12) 1px, transparent 1px);
  background-size: 34px 34px;
  pointer-events: none;
  mask-image: radial-gradient(ellipse 70% 70% at 50% 50%, #000 30%, transparent 100%);
}

.csr-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 28px;
  position: relative;
  z-index: 1;
}

/* ── Card ── */
.csr-card {
  background: #fff;
  border-radius: 24px;
  padding: 40px 36px 36px;
  border: 1px solid rgba(201, 162, 77, 0.12);
  box-shadow: 0 6px 32px rgba(0,0,0,0.05);
  transition: transform 0.5s var(--ease-out), box-shadow 0.5s var(--ease-out), border-color 0.4s;
  position: relative;
  overflow: hidden;
}

.csr-card::after {
  content: '';
  position: absolute;
  bottom: 0; left: 0; right: 0;
  height: 3px;
  background: var(--gold-grad);
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.55s var(--ease-out);
  border-radius: 0 0 2px 2px;
}

.csr-card:hover {
  transform: translateY(-10px);
  box-shadow: 0 24px 72px rgba(201, 162, 77, 0.14);
  border-color: rgba(201, 162, 77, 0.3);
}

.csr-card:hover::after {
  transform: scaleX(1);
}

/* Card top row */
.csr-card-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 28px;
}

/* Icon */
.csr-icon-wrap {
  width: 64px;
  height: 64px;
  border-radius: 18px;
  background: linear-gradient(135deg, rgba(246,196,83,0.15), rgba(201,162,77,0.08));
  border: 1px solid rgba(201,162,77,0.22);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.45s var(--ease-out), box-shadow 0.45s;
}

.csr-card:hover .csr-icon-wrap {
  transform: rotate(8deg) scale(1.08);
  box-shadow: 0 12px 36px rgba(201,162,77,0.25);
}

.csr-icon {
  font-size: 28px;
}

/* Card number watermark */
.csr-card-num {
  font-size: 13px;
  font-weight: 800;
  letter-spacing: 3px;
  color: rgba(201,162,77,0.3);
  font-variant-numeric: tabular-nums;
  transition: color 0.35s;
}

.csr-card:hover .csr-card-num {
  color: var(--gold);
}

/* Card content */
.csr-content h3 {
  font-size: 20px;
  font-weight: 700;
  color: var(--ink);
  margin-bottom: 14px;
  letter-spacing: -0.2px;
  transition: color 0.3s;
}

.csr-card:hover .csr-content h3 {
  color: var(--gold);
}

.csr-content p {
  font-size: 14.5px;
  line-height: 1.82;
  color: var(--text-muted);
  margin-bottom: 10px;
}

.csr-content p:last-child { margin-bottom: 0; }

/* Bottom accent line */
.csr-card-line {
  width: 28px;
  height: 2px;
  background: var(--gold-grad);
  border-radius: 2px;
  margin-top: 28px;
  transition: width 0.45s var(--ease-out);
}

.csr-card:hover .csr-card-line { width: 100%; }

/* ================================================================
   ACTIVITIES CTA SECTION
   ================================================================ */
.csr-activities {
  background: var(--ink);
  padding: 130px 0;
  overflow: hidden;
  position: relative;
}

/* Big ghost text */
.csr-activities-bg-text {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  font-size: clamp(100px, 18vw, 200px);
  font-weight: 900;
  letter-spacing: -8px;
  color: rgba(255,255,255,0.025);
  pointer-events: none;
  user-select: none;
  white-space: nowrap;
}

/* Top gold rule */
.csr-activities::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(246,196,83,0.5), transparent);
}

.csr-activities-inner {
  display: grid;
  grid-template-columns: 1.1fr 0.9fr;
  align-items: center;
  gap: 96px;
  position: relative;
  z-index: 1;
}

/* Text side */
.csr-activities-content .csr-tag {
  background: rgba(246, 196, 83, 0.1);
  border-color: rgba(246, 196, 83, 0.3);
  color: var(--gold-light);
}

.csr-activities-content h2 {
  font-size: clamp(36px, 4vw, 52px);
  font-weight: 700;
  margin: 20px 0 22px;
  color: #fff;
  letter-spacing: -0.5px;
  line-height: 1.2;
}

.csr-activities-content h2 em {
  font-style: italic;
  background: var(--gold-grad);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.csr-activities-content p {
  max-width: 480px;
  color: rgba(255,255,255,0.5);
  line-height: 1.82;
  margin-bottom: 44px;
  font-size: 15.5px;
}

/* Button */
.csr-btn {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 15px 36px;
  border-radius: 50px;
  background: var(--gold-grad);
  color: #111;
  font-weight: 700;
  font-size: 13.5px;
  text-decoration: none;
  text-transform: uppercase;
  letter-spacing: 1.2px;
  transition: transform 0.35s var(--ease-out), box-shadow 0.35s;
  box-shadow: 0 10px 36px rgba(246,196,83,0.3);
  position: relative;
  overflow: hidden;
}

.csr-btn::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(255,255,255,0.18), transparent);
  opacity: 0;
  transition: opacity 0.35s;
}

.csr-btn:hover {
  transform: translateY(-4px);
  box-shadow: 0 20px 56px rgba(246,196,83,0.45);
}

.csr-btn:hover::before { opacity: 1; }

.csr-btn svg {
  transition: transform 0.35s var(--ease-out);
}

.csr-btn:hover svg { transform: translateX(4px); }

/* Images side */
.csr-activities-images {
  position: relative;
  height: 480px;
}

.csr-activities-images .img {
  position: absolute;
  width: 295px;
  border-radius: 22px;
  object-fit: cover;
  border: 2px solid rgba(246,196,83,0.18);
  box-shadow: 0 32px 80px rgba(0,0,0,0.65);
  opacity: 0;
  transform: translateY(48px) scale(0.93);
  transition: all 1s var(--ease-out);
}

.img-left {
  left: 0;
  top: 40px;
  z-index: 2;
  height: 340px;
}

.img-right {
  right: 0;
  bottom: 0;
  z-index: 1;
  height: 300px;
}

.reveal.active ~ .csr-activities-images .img,
.csr-activities-inner.active .img-left {
  opacity: 1;
  transform: translateY(0) scale(1);
  transition-delay: 0.3s;
}

.csr-activities-inner.active .img-right {
  opacity: 1;
  transform: translateY(0) scale(1);
  transition-delay: 0.5s;
}

/* ================================================================
   RESPONSIVE
   ================================================================ */
@media (max-width: 1100px) {
  .csr-intro-grid,
  .csr-activities-inner {
    gap: 60px;
  }
}

@media (max-width: 900px) {
  .csr-grid {
    grid-template-columns: 1fr;
    max-width: 540px;
    margin: 0 auto;
  }

  .csr-intro-grid,
  .csr-activities-inner {
    grid-template-columns: 1fr;
    gap: 52px;
  }

  .csr-activities-inner {
    text-align: center;
  }

  .csr-activities-content p {
    margin: 0 auto 44px;
  }

  .csr-activities-images {
    height: 320px;
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 16px;
  }

  .csr-activities-images .img {
    position: relative;
    width: 45%;
    max-width: 240px;
    height: 220px;
    left: auto; right: auto; top: auto; bottom: auto;
  }
}

@media (max-width: 640px) {
  .csr-intro { padding: 80px 0 90px; }
  .csr-initiatives { padding: 80px 0 90px; }
  .csr-activities { padding: 80px 0; }

  .csr-intro-stat-row {
    gap: 20px;
  }

  .csr-card {
    padding: 32px 28px 28px;
  }

  .csr-activities-images {
    flex-direction: column;
    height: auto;
    gap: 16px;
  }

  .csr-activities-images .img {
    width: 100%;
    max-width: 320px;
    height: 200px;
  }
}
